#include <bits/stdc++.h>
#define int long long 
using namespace std;
int phi[1000005];
int f[1000005];
int n = 1e6;
int prime[500005], notprime[1000005];
void get_phi () {
	phi[1] = 1;
	for (int i = 2; i <= n; i++) {
		if (!notprime[i]) {
			prime[++prime[0]] = i;
			phi[i] = i - 1;
		}
		for (int j = 1; j <= prime[0] && i * prime[j] <= n; j++) {
			notprime[i * prime[j]] = 1;
			if (!(i % prime[j])) {
				phi[i * prime[j]] = prime[j] * phi[i];
				break;
			} else {
				phi[i * prime[j]] = phi[i] * (prime[j] - 1);
			}
		}
	}
}
signed main() {
	get_phi ();
	for (int i = 1; i <= n; i++) {
		for (int j = i; j <= n; j += i) {
			f[j] += (phi[i] * i + 1) >> 1;
		}
	}
	int T;
	cin >> T;
	while (T--) {
		cin >> n;
		cout << f[n] * n << '\n';
	}
	return 0;
}
